fun solve(s: String, order: Array<Long>, k: Long): Long {
    val n = s.length
    val replaced = BooleanArray(n)

    fun countValidSubstrings(): Long {
        var count = 0L
        for (i in 0 until n) {
            var j = i
            while j < n && !replaced[j] {
                j++
            }
            if (j < n) {
                count += (n - j).toLong()
            }
        }
        return count
    }

    var left = 0L
    var right = n.toLong()
    var result = -1L

    while (left <= right) {
        val mid = (left + right) / 2
        replaced.fill(false)
        for (i in 0 until mid) {
            replaced[order[i].toInt()] = true
        }
        val validCount = countValidSubstrings()
        if (validCount >= k) {
            result = mid
            right = mid - 1
        } else {
            left = mid + 1
        }
    }

    return result
}
